VALUES
  ('fire-eq-eng-moex-00583', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，有關室內及室外消防栓設備之設置，下列敘述何者正確？', '["6層以上建築物，供甲類場所使用，任何一層之樓地板面積在150 m2以上者，應設置室內消防栓設備", "總樓地板面積在100 m2以上之地下建築物，應設置室內消防栓設備", "中度危險工作場所，其建築物及儲存面積在3000 m2以上者，應設置室外消防栓設備", "設有室外消防栓設備之場所，在有效範圍內，得免設室內消防栓設備"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00584', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有一液化石油氣分裝場內之供應分裝台氣源之儲槽，其容積為10 m3，假設液化石油氣之比重為0.5（水=1）， 依各類場所消防安全設備設置標準第四編之規定，下列敘述何者錯誤？', '["依法可免設防護設備", "依法可設置室外消防栓", "依法可設置射水槍", "依法應設置滅火器"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00585', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '分裝場實施油氣灌裝之分裝台，其長、寬分別為15公尺及30公尺，如僅依面積檢討最小應設滅火器數 量，其法定最小B類滅火效能值應為？', '["40", "50", "60", "70"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00586', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依複合用途建築物判斷基準之規定，供設置標準第12條第1款至第4款各目用途使用之樓地板面積合計 小於供住宅使用之樓地板面積合計，且前者樓地板面積合計在50 m2以上時，該建築物視為下列何者？', '["住宅", "各目用途之建築物", "住宅或各目用途之建築物", "複合用途建築物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00587', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，有關滅火器之設置，下列敘述何者正確？', '["供設置標準第12條第2款至第4款使用之場所，各層樓地板面積每200平方公尺（含未滿）有一滅火 效能值", "設有滅火器之樓層，自樓面居室任一點至滅火器之步行距離在30公尺以下", "懸掛於牆上或放置滅火器箱中之滅火器，其上端與樓地板面之距離，18公斤以上者在1.5公尺以下", "大眾運輸工具每輛（節）配置2具"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00588', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防機關辦理建築物消防安全設備審查及查驗作業基準之規定，消防安全設備圖說審查及竣工查驗之 期限，以受理案件後X日內結案為原則。但供公眾使用建築物或構造複雜者，得視需要延長，最長不得 超過Y日。請問X、Y為下列何者？', '["10至14，20", "7至10，20", "7至10，30", "10至20，30"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00589', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防幫浦加壓送水裝置等及配管摩擦損失計算基準之規定，有關防止水溫上升用之排放裝置，下列敘 述何者錯誤？', '["設呼水槽時，防止水溫上升用排放管應從呼水管逆止閥之靠幫浦側連結", "防止水溫上升之排放管之配管中途須裝設控制閥", "防止水溫上升之排放管應使用口徑15 mm以上者", "防止水溫上升之排水管之流量，應使幫浦在全閉狀態下連續運轉時，不使幫浦內部水溫升高至35℃以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00590', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依原有合法建築物防火避難設施及消防設備改善辦法之規定，有關原有合法建築物10層以下之非防火構 造建築物，其主要構造部分使用不燃材料建造之建築物者，應按其總樓地板面積每X平方公尺，以具有 1小時防火時效之牆壁、樓地板及防火設備區劃分隔。請問X為多少？', '["300", "500", "1000", "1500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00591', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築法之規定，建築物之基礎、樑柱、承重牆壁、樓地板、屋架或屋頂，其中任何一種有過半之修理 或變更者，屬於建築物之何種行為？', '["新建", "增建", "改建", "修建"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00592', 'fire-eq-eng', 'fire-eq-eng-moex-107-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編之規定，有關建築技術用語定義，下列敘述何者錯誤？', '["總樓地板面積係建築物各層包括地下層、屋頂突出物及夾層等樓地板面積之總和", "門廳、走廊、樓梯間、廁所盥洗室、浴室、機械室、車庫等，不視為居室", "具有共同基地及共同空間或設備，並有5個住宅單位以上之建築物，稱為集合住宅", "有效採光面積未達居室樓地板面積5%者，可視為無窗戶居室"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "9b07ce4ecf30", "answer_pdf_sha1": "25368deb3403", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "501", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
